#include <iostream>

class IntArray
{
private:
    int m_length{};
    int* m_data{};

public:
    IntArray(int length)
        : m_length{ length }
        , m_data{ new int[length]{} }
    {
    }

    IntArray(const IntArray& src)
        : m_length{ src.m_length }
        , m_data{ new int[src.m_length] }
    {
        for (int i{ 0 }; i < m_length; ++i)
            m_data[i] = src.m_data[i];
    }

    IntArray& operator=(const IntArray& src)
    {
        if (this == &src)
            return *this;

        delete[] m_data;

        m_length = src.m_length;
        m_data = new int[m_length];
        for (int i{ 0 }; i < m_length; ++i)
            m_data[i] = src.m_data[i];

        return *this;
    }

    ~IntArray()
    {
        delete[] m_data;
    }

    int getLength() const { return m_length; }
    int& operator[](int index) { return m_data[index]; }
    int operator[](int index) const { return m_data[index]; }
};

int main()
{
    int n{};
    std::cin >> n;

    IntArray original(n);
    for (int i{ 0 }; i < n; ++i)
        std::cin >> original[i];

